VALUES
  ('pukao-e0adf6cd-moex-00106', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '國立大學學生甲對學校所為之記過處分，經依法提出申訴，仍不服申訴評議決定時，應如何救濟？', '["甲得以申訴決定違法或不當且侵害其權益，逕向教育部提起再申訴", "甲得以申訴決定違法且侵害其權利，逕向行政法院提起撤銷訴訟", "甲得以申訴決定違法或不當且侵害其權益，逕向教育部提起訴願", "甲得以申訴決定違法且侵害其權益，以該學校為被告，逕提起國家賠償訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00107', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於訴願之管轄，下列敘述何者正確？', '["不服鄉公所之行政處分者，向縣政府所屬各級機關提起訴願", "不服縣政府所屬各級機關之行政處分者，向中央主管部、會、行、處、局、署提起訴願", "不服中央各部、會、行、處、局、署所屬機關之行政處分者，向各部、會、行、處、局、署提起訴願", "不服中央各院之行政處分者，向總統府提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00108', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '下列公法上爭議何者由行政法院所審理？', '["政黨違憲解散案", "總統彈劾案", "選舉罷免事件", "收容聲請事件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00109', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '主管機關命甲自行拆除違建，甲對此處分不服提起訴願，於訴願審議期間，主管機關已將該違建拆除 完畢，若其訴願經駁回，甲仍不服，應提起何種訴訟以為救濟？', '["撤銷訴訟", "課予義務訴訟", "違法確認訴訟", "一般給付訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00110', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '依行政程序法之規定，下列何者非屬法規命令無效情形？', '["牴觸憲法或法律者", "無法律之授權而剝奪或限制人民之自由、權利者", "其訂定應經其他機關核准，而未經核准者", "尚未經立法院同意備查者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00111', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於行政訴訟訴訟費用之敘述，下列何者正確？', '["適用簡易訴訟程序之事件，徵收裁判費新臺幣4,000元", "依行政訴訟法第198條為情況判決時，其訴訟費用由被告負擔", "基於行政訴訟之公益性，行政訴訟由國家負擔訴訟費用", "當事人無資力支出訴訟費用者，行政法院得依職權以裁定准予訴訟救助"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00112', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '甲之外籍配偶乙向我國駐外使領館申請入臺簽證，但經調查甲、乙婚姻真實性尚有可疑之處，乃拒絕 核發簽證。依憲法法庭裁判意旨，下列敘述何者正確？', '["因入臺簽證僅外國人須申請，甲非申請人故無提起行政救濟之權利", "甲與乙僅具有事實上或情感上之利害關係，故甲不得提起行政救濟", "基於維護婚姻與家庭關係，甲得提起課予義務訴訟尋求救濟", "因配偶經營共同生活之婚姻自由受侵害，甲得對該拒絕處分提起撤銷訴訟尋求救濟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00113', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於因公共設施設置或管理有欠缺，人民請求國家賠償之敘述，下列何者錯誤？', '["賠償義務機關，係指公共設施之管理機關", "管理機關，係指法令所定之管理機關或依法代為管理之機關", "設施雖非由國家設置，但事實上由其管理，並直接供公共或公務目的使用，仍屬國家賠償法所稱之 公共設施", "公共設施因設置或管理，致人民人身自由受損害者，國家不負損害賠償責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00114', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於國家賠償之敘述，下列何者正確？', '["國家賠償請求權人，只能請求所受損害，不得請求其所失利益", "國家負損害賠償責任者，應以金錢為之。但以回復原狀為適當者，得依請求，回復損害發生前原狀", "國家賠償之請求權，自損害發生時起，因2年間不行使而消滅", "外國人為被害人時，不得請求國家賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00115', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-113-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於國家賠償法所規定之公務員國家賠償責任，下列敘述何者正確？', '["給付行政措施，不生公務員國家賠償責任", "受委託行使公權力者，於行使公權力時，亦適用公務員國家賠償責任", "為求人民權利保障之完整性，縱使公務員並無故意或過失，亦構成公務員國家賠償責任", "為使人民權利獲得全面性之保障，故公務員之不法行為與損害發生間，不以具有因果關係為必要"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "410", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL)
